'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/hooks/use-auth';
import { reportsService } from '@/lib/services/admin-service';
import { DashboardMetrics } from '@/lib/types-extended';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Users, ShoppingCart, DollarSign, ShieldCheck,
  Truck, Activity, TrendingUp, Clock,
} from 'lucide-react';

function StatCard({
  title, value, icon: Icon, sub, color = 'text-primary',
}: {
  title: string;
  value: string | number;
  icon: React.ElementType;
  sub?: string;
  color?: string;
}) {
  return (
    <Card>
      <CardContent className="pt-6">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-sm text-muted-foreground">{title}</p>
            <p className="text-2xl font-bold mt-1">{value}</p>
            {sub && <p className="text-xs text-muted-foreground mt-1">{sub}</p>}
          </div>
          <Icon className={`h-8 w-8 ${color} opacity-80`} />
        </div>
      </CardContent>
    </Card>
  );
}

export default function AdminDashboardPage() {
  const { user, token, isLoading } = useAuth();
  const router = useRouter();
  const [metrics, setMetrics] = useState<DashboardMetrics | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (isLoading) return;
    if (!user) { router.push('/auth/login'); return; }
    if (user.role !== 'admin') { router.push('/dashboard'); return; }
  }, [user, isLoading, router]);

  useEffect(() => {
    if (!token || !user || user.role !== 'admin') return;
    reportsService.getDashboardMetrics(token)
      .then(setMetrics)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  }, [token, user]);

  if (isLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto py-8 px-4">
        <p className="text-destructive text-center">{error}</p>
      </div>
    );
  }

  const fmt = (n: number) =>
    n >= 1000 ? `${(n / 1000).toFixed(1)}k` : String(n);

  const fmtCurrency = (n: number) =>
    new Intl.NumberFormat('en-ET', { style: 'currency', currency: 'ETB', maximumFractionDigits: 0 }).format(n);

  return (
    <div className="container mx-auto py-8 px-4 space-y-8">
      <div>
        <h1 className="text-2xl font-bold">Admin Dashboard</h1>
        <p className="text-muted-foreground text-sm mt-1">Platform overview</p>
      </div>

      {/* Stats grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard
          title="Total Users"
          value={metrics ? fmt(metrics.total_users) : '—'}
          icon={Users}
          sub="registered accounts"
          color="text-blue-500"
        />
        <StatCard
          title="Total Orders"
          value={metrics ? fmt(metrics.total_orders) : '—'}
          icon={ShoppingCart}
          sub={metrics ? `${metrics.orders_today} today` : undefined}
          color="text-orange-500"
        />
        <StatCard
          title="Total Revenue"
          value={metrics ? fmtCurrency(metrics.total_revenue) : '—'}
          icon={DollarSign}
          sub={metrics ? `${fmtCurrency(metrics.revenue_today)} today` : undefined}
          color="text-green-500"
        />
        <StatCard
          title="Active Today"
          value={metrics ? fmt(metrics.active_users_today) : '—'}
          icon={Activity}
          sub="active users"
          color="text-purple-500"
        />
      </div>

      {/* Secondary stats */}
      <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
        <StatCard
          title="Pending Verifications"
          value={metrics ? metrics.pending_verifications : '—'}
          icon={ShieldCheck}
          color="text-yellow-500"
        />
        <StatCard
          title="Pending Transports"
          value={metrics ? metrics.pending_transports : '—'}
          icon={Truck}
          color="text-cyan-500"
        />
        <StatCard
          title="Orders Today"
          value={metrics ? metrics.orders_today : '—'}
          icon={TrendingUp}
          color="text-rose-500"
        />
      </div>

      {/* Quick links */}
      <div>
        <h2 className="text-lg font-semibold mb-4">Quick Actions</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          {[
            { label: 'Manage Users', href: '/admin/users', icon: Users },
            { label: 'Verifications', href: '/admin/verification', icon: ShieldCheck },
            { label: 'Reports', href: '/admin/reports', icon: TrendingUp },
            { label: 'Audit Logs', href: '/admin/audit', icon: Clock },
          ].map(({ label, href, icon: Icon }) => (
            <button
              key={href}
              onClick={() => router.push(href)}
              className="flex flex-col items-center gap-2 p-4 rounded-lg border bg-card hover:bg-muted transition-colors text-sm font-medium"
            >
              <Icon className="h-5 w-5 text-primary" />
              {label}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}
